+package metrics
+
+import "testing"
+
+// TestHistogramBoundaryCumulative checks that a value exactly equal to a
+// bucket's upper bound is counted in that bucket (and every bucket above it).
+func TestHistogramBoundaryCumulative(t *testing.T) {
+	h := &Histogram{
+		bounds: []float64{1, 2, 5},
+		counts: make([]uint64, 3),
+	}
+	h.Observe(2) // exactly equals the second bound
+
+	if h.counts[0] != 0 {
+		t.Fatalf("bucket0 = %d, want 0", h.counts[0])
+	}
+	if h.counts[1] != 1 {
+		t.Fatalf("bucket1 = %d, want 1", h.counts[1])
+	}
+	if h.counts[2] != 1 {
+		t.Fatalf("bucket2 = %d, want 1", h.counts[2])
+	}
+	if h.count != 1 {
+		t.Fatalf("count = %d, want 1", h.count)
+	}
+	if h.sum != 2 {
+		t.Fatalf("sum = %v, want 2", h.sum)
+	}
+}

