+package metrics
+
+import "testing"
+
+// TestHistogramBoundaryBucket is a thin regression check: a value equal to a
+// bucket's upper bound must be counted in that bucket (cumulative semantics).
+func TestHistogramBoundaryBucket(t *testing.T) {
+	reg := New()
+	h := reg.NewHistogram("boundary_test", "boundary test histogram", []float64{1, 2, 5})
+	h.Observe(2)
+	if h.buckets[1] != 1 {
+		t.Fatalf("value equal to bound should be counted in its own bucket: buckets=%v", h.buckets)
+	}
+}

